// Number型の例
var num = 123;
console.log(num); // 予想される出力: 123

// String型の例
var str = "Hello, World!";
console.log(str); // 予想される出力: 'Hello, World!'

// Boolean型の例
var bool = true;
console.log(bool); // 予想される出力: true

// Null型の例
var n = null;
console.log(n); // 予想される出力: null

// Undefined型の例
var und;
console.log(und); // 予想される出力: undefined

// 配列の例
var arr = [1, 2, 3];
console.log(arr); // 予想される出力: [1, 2, 3]

// オブジェクトの例
var obj = {name: "John", age: 30};
console.log(obj); // 予想される出力: {name: "John", age: 30}

// データ型の変換の例
var num = 123;
var str = num.toString();
console.log(str); // 予想される出力: '123'

// 配列から値を取り出す例
var arr = ['apple', 'banana', 'cherry'];
console.log(arr[1]); // 予想される出力: 'banana'

// オブジェクトから値を取り出す例
var obj = {name: "John", age: 30};
console.log(obj.name); // 予想される出力: 'John'

// Booleanの例
var bool = true;
console.log(bool); // 予想される出力: true

// Undefinedの例
var und;
console.log(und); // 予想される出力: undefined

// Nullの例
var nul = null;
console.log(nul); // 予想される出力: null

// 配列の長さを取得する例
var arr = ['apple', 'banana', 'cherry'];
console.log(arr.length); // 予想される出力: 3

// 配列への要素の追加の例
var arr = ['apple', 'banana', 'cherry'];
arr.push('date');
console.log(arr); // 予想される出力: ['apple', 'banana', 'cherry', 'date']

// 配列からの要素の削除の例
var arr = ['apple', 'banana', 'cherry'];
arr.pop();
console.log(arr); // 予想される出力: ['apple', 'banana']

// 配列の要素のソートの例
var arr = ['apple', 'cherry', 'banana'];
arr.sort();
console.log(arr); // 予想される出力: ['apple', 'banana', 'cherry']

// データ型の確認の例
var num = 123;
console.log(typeof num); // 予想される出力: 'number'

// 文字列と数値の変換の例
var str = '123';
var num = Number(str);
console.log(typeof num); // 予想される出力: 'number'

var num2 = 456;
var str2 = num2.toString();
console.log(typeof str2); // 予想される出力: 'string'

// '=='と'==='の違いの例
console.log(123 == '123'); // 予想される出力: true
console.log(123 === '123'); // 予想される出力: false
